$ErrorActionPreference = "Stop"
$ProjectRoot = Split-Path -Parent $PSScriptRoot
$FlutterRoot = Join-Path $ProjectRoot "Flutter"
$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)

Push-Location $FlutterRoot
try {
  flutter pub add sqflite path path_provider flutter_riverpod
  if ($LASTEXITCODE -ne 0) { throw "Adding runtime packages failed." }
  flutter pub add --dev sqflite_common_ffi
  if ($LASTEXITCODE -ne 0) { throw "Adding test packages failed." }
} finally { Pop-Location }

$RelativePath = "Flutter\lib\data\database\schema_v1.dart"
$FullPath = Join-Path $ProjectRoot $RelativePath
$Parent = Split-Path -Parent $FullPath
if (-not (Test-Path $Parent)) { New-Item -ItemType Directory -Force -Path $Parent | Out-Null }
$Content = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(""))
[IO.File]::WriteAllText($FullPath, $Content, $Utf8NoBom)
Write-Host "Wrote $RelativePath"

$RelativePath = "Flutter\lib\data\database\app_database.dart"
$FullPath = Join-Path $ProjectRoot $RelativePath
$Parent = Split-Path -Parent $FullPath
if (-not (Test-Path $Parent)) { New-Item -ItemType Directory -Force -Path $Parent | Out-Null }
$Content = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(""))
[IO.File]::WriteAllText($FullPath, $Content, $Utf8NoBom)
Write-Host "Wrote $RelativePath"

$RelativePath = "Flutter\test\data\database\app_database_test.dart"
$FullPath = Join-Path $ProjectRoot $RelativePath
$Parent = Split-Path -Parent $FullPath
if (-not (Test-Path $Parent)) { New-Item -ItemType Directory -Force -Path $Parent | Out-Null }
$Content = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(""))
[IO.File]::WriteAllText($FullPath, $Content, $Utf8NoBom)
Write-Host "Wrote $RelativePath"

Push-Location $FlutterRoot
try {
  dart format lib test
  if ($LASTEXITCODE -ne 0) { throw "dart format failed." }
  flutter analyze
  if ($LASTEXITCODE -ne 0) { throw "flutter analyze failed." }
  flutter test
  if ($LASTEXITCODE -ne 0) { throw "flutter test failed." }
} finally { Pop-Location }

Write-Host "SQLite database layer installed and validated successfully."
Write-Host "Schema statements: 25"